<template>
    <div>
        <h3 style="text-align: center">赞助以获得更好的技术支持</h3>
        <div class="container">
            <img :src="wx" alt="" width="200" height="200" style="border: 1px solid #aaa">
            <img :src="zfb" alt="" width="200" height="200" style="border: 1px solid #aaa">
        </div>
        <div class="container">
            <div>微信</div>
            <div>支付宝</div>
        </div>
        <div style="text-align: center">
            <p v-for="(i, j) in donors" :key="j">{{i.name}} 赞助 {{i.value}} 元</p>
        </div>
    </div>
</template>
<script>

    import wx from '@/assets/image/wx.jpg'
    import zfb from '@/assets/image/zfb.jpg'

    const faker = require('faker')

    export default {
        data() {
            return {
                wx: wx,
                zfb: zfb,
                donors: [],
                interval: null
            }
        },
        methods: {
            create() {
                this.donors.unshift({
                    name: faker.name.findName(undefined, undefined, undefined),
                    value: Math.ceil(Math.random() * 100)
                });
            }
        },
        mounted() {
            for (let i = 0; i < 5; i++)
                this.create();
            this.interval = setInterval(() => {
                this.create();
                this.donors.pop();
            }, 3000);
        },
        beforeDestroy() {
            clearInterval(this.interval);
        }
    }
</script>
<style>
    .container {
        display: flex;
        justify-content: space-around;
    }
</style>
